-static const std::string &checkPath(const std::string &path,
-                                    bool missingPathFatal = false) {
-  if (std::filesystem::exists(path)) {
-    return path;
-  }
-  if (!missingPathFatal) {
-    LOG(INFO) << "Didn't find " << path;
-    static const std::string empty = "";
-    return empty;
-  } else {
-    LOG(FATAL) << "Didn't find " << path;
-  }
-}
