+void LLVMIRGen::updateAttributes(llvm::Module *M) {
+  // Add no-frame-pointer-elim=true attribute. It helps with profiling and
+  // debugging the produced code.
+  for (auto &FF : *M) {
+    if (FF.isDeclaration()) {
+      continue;
+    }
+    if (FF.hasFnAttribute("no-frame-pointer-elim") ||
