+        F->getParent()->uniqueTypeWithNewShape(curNode->getType(resultIdx),
+                                               outDims));
+    F->addNode(clone);
+
+    // Loop over all of the inputs and slice those inputs that need to be
+    // sliced, and set them on the clone.
+    for (int j = 0, e = curNode->getNumInputs(); j < e; j++) {
+      int dim = splitDims[j];
+      if (dim == -1) {
