+      offsets, getGlowNodeValueForValue(
+                   inputs[BatchedUnaryEmbeddingsBagsInputs::offsets]));
+
+  auto *EB = F_.createBatchedUnaryEmbeddingsBags(
+      "BatchedUnaryEmbeddingsBags", weights, tableOffsets, indices, offsets);
