+                glow::Kinded::Kind::TanhNodeKind ||
+            CN->getNumInputs() <= concatSplitSize) {
+          continue;
+        }
+        auto tanhNode =
+            llvm::dyn_cast<TanhNode>(concatUsers.begin()->getUser());
+        auto dim = CN->getDim();
