+    changed = true;
+  }
+
+  // Remove fused Relu.
+  for (auto &N : F->getNodes()) {
+    changed |= removeFusedIdentityRelu<ConvolutionNode>(&N);
+    changed |= removeFusedIdentityRelu<ChannelwiseQuantizedConvolutionNode>(&N);
+  }
+
+  return changed;
