diff --git a/lib/Optimizer/Lower/Lower.cpp b/lib/Optimizer/Lower/Lower.cpp
index bdf08c743..aefaf665d 100644
--- a/lib/Optimizer/Lower/Lower.cpp
+++ b/lib/Optimizer/Lower/Lower.cpp
