+  const auto &t = variableMetas[0].shape<TensorShape>();
+  // Load dim parameter if provided
+  int64_t dim = 0;
+  bool dimProvided = false;
+  if (variableMetas.size() == 2) {
+    dimProvided = true;
+    dim = variableMetas[1].intValue[0];
+    if (dim < 0) {
+      dim += t.size();
